sp_angular_provider.script:
/* Use this Directive to show a list in a popover
Note: AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
Usage in a widget's HTML:
		<div id="popoverWrapperList" ng-mouseenter="c.avatarMouseEnter()" >
			<dtech-popover-list dtech-param-object="data.popoverListRecord" ng-mouseleave="c.avatarMouseLeave()"></dtech-popover-list>
		</div>


	dtechParamObject maps to dtech-param-object
	popoverListOptions maps to popover-list-options

	Here are two ways to get the HTML for the directive to use:
	1. template: htmlTemplate
		var htmlTemplate = '<div>some simple html goes here</div>' + '<div> as a contactenated string</div'
	2. templateUrl: getTemplateUrl('x_153465_discovert_dtechPopoverList.html')
	    In UI Macros, create a new macro, remove default XML code and carefully write the desired HTML, lacks syntax checking for HTML.

//
// Copyrights belong to Discover Technologies LLC. © 2022 Discover Technologies LLC
// Script Continued Below
// 2.8 | 2022-03-10 | mmcc | STRY0114672 - Org Hierarchy Full Screen- Tree Node- Any Members List- Update to Popover Panel
//  Create Directive
//										   
*/
function dtechPopoverList(getTemplateUrl, spModal) {

	var jsController =
		function($scope) {

			$scope.openSomeModal = function(modalType) {
				// Host widget's Client controller builds the data
				var widgetObject = $scope.popoverListOptions.objWidget;

				_removePopoverList();

				switch (modalType) {
					case 'formModal':
						_openFormModal(widgetObject);
						break;
					default:
						_openListModal(widgetObject);
				}

			};

			// Example HTML <span class="dtech-avatar-link" ng-click="openUserProfileModal()"> Open Contact Page</span>
			$scope.openUserProfileModal = function(userSysId) {
				_removePopoverList();

				spModal.open({
					title: 'User Profile',
					backdrop: 'static',
					widget: 'tasker-user-profile',
					widgetInput: {
						sys_id: userSysId,
						isModal: true
					},
					size: 'lg',
					buttons: [],
					footerStyle: {
						'display': 'none'
					}
				});
			};

			function _openFormModal(widgetObject) {
				spModal.open({
					title: widgetObject.title,
					message: '',
					backdrop: 'static',
					widget: 'discovertasker-formtab',
					widgetInput: {
						table: widgetObject.table,
						sys_id: widgetObject.sys_id,
						parent: widgetObject.parent?widgetObject.parent:'',
						u_ou_parent: widgetObject.u_ou_parent?widgetObject.u_ou_parent:'',
						filter: widgetObject.filter?widgetObject.filter:'',
						query: widgetObject.query?widgetObject.query:'',
						view: widgetObject.view,
						hideRelatedLists: true,
						omitHeader: widgetObject.omitHeader,
						bifold: false,
						hideAttachmentBtn: true,
						isModal: true
					},
					shared: {},
					size: 'lg',
					buttons: [],
					footerStyle: {
						'display': 'none'
					}
				});
			}

			function _openListModal(widgetObject) {
				spModal.open({
					title: widgetObject.title,
					message: '',
					backdrop: 'static',

					widget: 'discovertasker-widget-data-table',
					widgetInput: {
						o: widgetObject.o,
						d: widgetObject.d,
						table: widgetObject.table,
						filter: widgetObject.filter,
						show_new: true,
						open_new_in_modal: true,
						open_row_details_in_modal: true,
						view: widgetObject.view,
						hideAttachmentBtn: true,
						isModal: true
					},
					size: 'lg',
					buttons: [],
					footerStyle: {
						'display': 'none'
					}
				});
			}

			function _removePopoverList() {
				var popoverDiv = angular.element(document.getElementById('popoverWrapperList'))[0];
				popoverDiv.style.display = "none";
			}

		};

	return {
		restrict: 'E',
		scope: {
			dtechParamObject: '<', // @: string 1 way, =: object 2 way, <: object 1 way
			popoverListOptions: '<'
		},
		controller: jsController,
		templateUrl: getTemplateUrl('x_153465_discovert_dtechPopoverList.html')
	};
}
